<template>
  <!-- 开场动画 -->
  <OpeningVideo v-if="showOpening" @done="showOpening = false" />

  <Transition name="app-fade">
    <div class="app" v-if="!showOpening">
      <header class="app__header">
        <h1 class="app__title" @click="onTitleClick"> 亡命十三街</h1>
        <p class="app__subtitle">designed by Lynacine&made by myracler </p>
      </header>

    <!-- 彩蛋弹窗 -->
    <Transition name="easter">
      <div v-if="easterEgg" class="app__easter" @click="easterEgg = false">
        <img class="app__easter-avatar" src="data:image/png;base64," alt="Eclipse">
        <span class="app__easter-text">Eclipse is watching you~ ✨</span>
      </div>
    </Transition>

    <!-- 开始界面 -->
    <GameSetup
      v-if="!gameStarted"
      :playerCount="playerCount"
      :playerNames="playerNames"
      :playerChars="playerChars"
      :useWeather="useWeather"
      :allSelected="allSelected"
      :availableChars="availableChars"
      @update:playerCount="playerCount = $event"
      @update:useWeather="useWeather = $event"
      @update:playerName="(idx, name) => playerNames[idx] = name"
      @selectChar="selectChar"
      @startGame="startGame"
    />

    <!-- 游戏界面 -->
    <GameShell
      v-else
      :state="gameState"
      @restart="resetGame"
    />
    </div>
  </Transition>
</template>

<script setup>
import { ref } from 'vue'
import GameShell from './components/GameShell.vue'
import GameSetup from './components/GameSetup.vue'
import OpeningVideo from './components/OpeningVideo.vue'
import { useGameController } from './composables/useGameController.js'

const {
  gameState,
  gameStarted,
  playerCount,
  playerNames,
  playerChars,
  useWeather,
  allSelected,
  availableChars,
  selectChar,
  startGame,
  resetGame
} = useGameController()

// 开场动画
const showOpening = ref(true)

// 彩蛋
const easterEgg = ref(false)
let titleClickTimer = null

function onTitleClick() {
  if (titleClickTimer) {
    clearTimeout(titleClickTimer)
    titleClickTimer = null
    easterEgg.value = true
    setTimeout(() => { easterEgg.value = false }, 3500)
  } else {
    titleClickTimer = setTimeout(() => {
      titleClickTimer = null
    }, 600)
  }
}
</script>

