  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(0, 0, 0, 0.85);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  color: #fff;
  padding: 16px 28px;
  border-radius: 12px;
  font-size: 18px;
  font-weight: bold;
  z-index: 999;
  cursor: pointer;
  text-align: center;
  box-shadow: 0 0 30px rgba(255, 111, 0, 0.4);
}
.app__easter-avatar {
  width: 56px;
  height: 56px;
  border-radius: 50%;
  object-fit: cover;
  border: 2px solid rgba(255, 111, 0, 0.5);
  animation: avatarFloat 2s ease-in-out infinite;
}

